WHERE r.deleted=0

    AND (sp.student_no LIKE CONCAT('%', #{query.keyword}, '%') OR sp.chinese_name LIKE CONCAT('%', #{query.keyword}, '%') OR sp.english_name LIKE CONCAT('%', #{query.keyword}, '%'))

AND r.major_id=#{query.majorId}
AND r.grade_id=#{query.gradeId}
AND r.class_id=#{query.classId}
AND r.student_status=#{query.studentStatus}
